import{G as a,c as i,b as t,ae as n}from"./chunks/framework.Cpb2nuHT.js";const o=JSON.parse('{"title":"GitHub经常出现push或pull超时","description":"","frontmatter":{"title":"GitHub经常出现push或pull超时","date":"2025/5/22","tags":["Github","Git"],"author":"花木凋零成兰","hiddenCover":true},"headers":[],"relativePath":"Git/GitHub经常出现push或pull超时.md","filePath":"Git/GitHub经常出现push或pull超时.md","lastUpdated":1773103236000}'),l={name:"Git/GitHub经常出现push或pull超时.md"};function p(e,s,h,r,k,u){return t(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1747872000000"},[...s[0]||(s[0]=[n(`<h1 id="github经常出现push或pull超时" tabindex="-1">GitHub经常出现push或pull超时 <a class="header-anchor" href="#github经常出现push或pull超时" aria-label="Permalink to &quot;GitHub经常出现push或pull超时&quot;">​</a></h1><h2 id="解决办法" tabindex="-1">解决办法 <a class="header-anchor" href="#解决办法" aria-label="Permalink to &quot;解决办法&quot;">​</a></h2><p>GitHub 是国外的开源项目平台, 而且国内访问节点较少, 容易出现连接超时的情况;</p><p>最好的办法是使用科学工具进行访问, 同时需要再git中配置相关端口进行访问, 如下所示:</p><div class="language-java vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 工具是socks类型的, 找到自己使用工具的端口</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git config </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">global http.https</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//github.com.proxy socks5://127.0.0.1:工具的port</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"># 如果工具是http类型的，如下设置：</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git config </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">global http.https</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//github.com.proxy &#39;http://127.0.0.1:代理的port&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#取消代理</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">git config </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">global </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">unset http.https</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//github.com.proxy</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://blog.csdn.net/weixin_43914200/article/details/121316043" target="_blank" rel="noreferrer">github push/pull老是超时解决方法</a></li></ul>`,7)])])}const c=a(l,[["render",p]]);export{o as __pageData,c as default};
